    #[test]
    fn syn_type_from_ast_expr_maps_go_primitives_without_postpass() {
        fn ident(name: &'static str) -> crate::ast::Ident<'static> {
            crate::ast::Ident {
                name_pos: crate::token::Position::default(),
                name,
                obj: None,
            }
        }

        let int_ty: syn::Type = crate::ast::Expr::Ident(ident("int")).into();
        let string_ty: syn::Type = crate::ast::Expr::Ident(ident("string")).into();
        let byte_slice_ty: syn::Type = crate::ast::Expr::ArrayType(crate::ast::ArrayType {
            lbrack: crate::token::Position::default(),
            len: None,
            elt: Box::new(crate::ast::Expr::Ident(ident("byte"))),
        })
        .into();
        let map_ty: syn::Type = crate::ast::Expr::MapType(crate::ast::MapType {
            map: crate::token::Position::default(),
            key: Box::new(crate::ast::Expr::Ident(ident("string"))),
            value: Box::new(crate::ast::Expr::Ident(ident("uint64"))),
        })
        .into();

        assert_eq!(quote! { #int_ty }.to_string(), "isize");
        assert_eq!(quote! { #string_ty }.to_string(), "String");
        assert_eq!(quote! { #byte_slice_ty }.to_string(), "Vec < u8 >");
        assert_eq!(
            quote! { #map_ty }.to_string(),
            "std :: collections :: HashMap < String , u64 >"
        );
    }

    #[test]
    fn general_type_conversion_lowers_to_cast_without_postpass() {
        let parsed = parse_file(
            "test.go",
            r#"
package main

func main() {
	var x uint8
	_ = int(x)
}
"#,
        )
        .unwrap();
        let mut env = super::typeinfer::TypeEnv::new();
        env.scan_file(&parsed);
        super::set_type_env(env);

        let crate::ast::Decl::FuncDecl(func) = parsed.decls.into_iter().next().unwrap() else {
            panic!("expected function declaration");
        };
        let body = func.body.expect("expected function body");
        let mut stmts = body.list.into_iter();
        let Some(crate::ast::Stmt::DeclStmt(_)) = stmts.next() else {
            panic!("expected var declaration");
        };
        let Some(crate::ast::Stmt::AssignStmt(assign)) = stmts.next() else {
            panic!("expected assignment");
        };
        let Some(crate::ast::Expr::CallExpr(call)) = assign.rhs.into_iter().next() else {
            panic!("expected conversion call");
        };
        let expr: syn::Expr = crate::ast::Expr::CallExpr(call).into();
        super::set_type_env(super::typeinfer::TypeEnv::new());

        assert_eq!(quote! { #expr }.to_string(), "((x) as isize)");
    }

