    #[test]
    fn equality_shapes_lower_from_go_types_without_postpass() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                func checks(err error, value any, fn func(), p *int, q *int) bool {
                    return err == nil &&
                        nil != value &&
                        fn == nil &&
                        p == q
                }
            "#,
        )
        .unwrap();

        let compiled = compile(parsed).unwrap();
        let output = quote! { #compiled }.to_string();

        assert!(
            output.contains("__gors_as_any () . is_none ()"),
            "expected error nil comparison to use runtime interface hook: {output}"
        );
        assert!(
            output.contains("! crate :: builtin :: interface_is_nil"),
            "expected any nil comparison to use runtime interface nil check: {output}"
        );
        assert!(
            output.contains("fn_) . lock () . unwrap () . is_none ()"),
            "expected function nil comparison to inspect the function cell: {output}"
        );
        assert!(
            output.contains("crate :: builtin :: GorsPtr :: ptr_eq"),
            "expected pointer equality to use pointer-cell identity: {output}"
        );
        assert!(
            !output.contains("Box :: new"),
            "expected equality lowering not to depend on Box::new normalization: {output}"
        );
    }

    #[test]
    fn pointer_receiver_field_comparison_lowers_without_postpass() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                type node struct {
                    next *node
                }

                func (n *node) different() bool {
                    return n.next != n
                }
            "#,
        )
        .unwrap();

        let compiled = compile(parsed).unwrap();
        let output = quote! { #compiled }.to_string();

        assert!(
            output.contains("self . next != self as * mut Self"),
            "expected source lowering to cast current pointer receiver directly: {output}"
        );
        assert!(
            !output.contains("self . next != self }"),
            "expected pointer receiver comparison not to need a generated-Rust cleanup: {output}"
        );
    }

    #[test]
    fn self_pointer_field_nil_and_unsafe_assignment_use_raw_receiver_pointer() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                import "unsafe"

                type node struct {
                    next *node
                }

                func (n *node) init() bool {
                    if n.next == nil {
                        n.next = (*node)(unsafe.Pointer(n))
                    }
                    return n.next == n
                }
            "#,
        )
        .unwrap();

        let compiled = compile(parsed).unwrap();
        let output = quote! { #compiled }.to_string();

        assert!(
            output.contains("self . next) . is_null"),
            "expected nil check on raw self-pointer field to use raw pointer null check: {output}"
        );
        assert!(
            output.contains("self . next = self as * mut Self"),
            "expected unsafe receiver assignment to preserve the raw self pointer: {output}"
        );
        assert!(
            !output.contains("self . next = (< crate :: builtin :: GorsPtr"),
            "expected raw self-pointer assignment not to materialize a GorsPtr default: {output}"
        );
    }

