    #[test]
    fn it_should_reject_non_addressable_assignment_lhs() {
        assert_invalid_assignment(
            r#"
                package main

                const c = 1

                func main() {
                    c = 2
                }
            "#,
        );
        assert_invalid_assignment(
            r#"
                package main

                type S struct { X int }

                func main() {
                    S{X: 1}.X = 2
                }
            "#,
        );
        assert_invalid_assignment(
            r#"
                package main

                func main() {
                    [1]int{1}[0] = 2
                }
            "#,
        );
        assert_unsupported_construct(
            r#"
                package main

                const c = 1

                func main() {
                    c++
                }
            "#,
            "operand must be addressable or a map index",
        );
        assert_invalid_assignment(
            r#"
                package main

                const c = 1

                func main() {
                    for c = range []int{1} {
                    }
                }
            "#,
        );
    }

