    #[test]
    fn local_item_shadowing_is_lowered_scope_aware_without_postpass() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                func helper() int { return 7 }

                func main() {
                    _ = helper()
                    helper := 3
                    _ = helper
                }
            "#,
        )
        .unwrap();

        let compiled = compile(parsed).unwrap();
        let output = printer::generate(compiled).unwrap();

        assert!(output.contains("let _ = helper();"), "{output}");
        assert!(output.contains("let mut helper__local = 3;"), "{output}");
        assert!(output.contains("let _ = helper__local;"), "{output}");
        assert!(!output.contains("helper__local();"), "{output}");
    }

    #[test]
    fn final_return_simplifies_during_function_lowering_without_postpass() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                type Counter int

                func value() int {
                    if true {
                        return 1
                    }
                    return 2
                }

                func (c Counter) get() int {
                    return int(c)
                }

                func named() (x int) {
                    return 3
                }
            "#,
        )
        .unwrap();

        let compiled = compile(parsed).unwrap();
        let output = quote! { #compiled }.to_string();

        assert!(output.contains("{ return 1 } 2"), "{output}");
        assert!(!output.contains("return 2"), "{output}");
        assert!(!output.contains("return x"), "{output}");
        assert!(
            !output.contains("fn get (& self) -> isize { return"),
            "{output}"
        );
    }

    #[test]
    fn static_false_pruning_uses_go_constants_without_postpass() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                func main() {
                    if false {
                        println("dead")
                    } else {
                        println("live")
                    }

                    flag := false
                    flag = true
                    if flag {
                        println("kept")
                    }
                }
            "#,
        )
        .unwrap();

        let compiled = compile(parsed).unwrap();
        let output = printer::generate(compiled).unwrap();

        assert!(!output.contains("dead"), "{output}");
        assert!(output.contains("live"), "{output}");
        assert!(output.contains("if flag"), "{output}");
        assert!(output.contains("kept"), "{output}");
    }

    #[test]
    fn it_should_not_treat_shadowed_predeclared_call_as_builtin() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                func main() {
                    print()
                }
            "#,
        )
        .unwrap();
        let crate::ast::Decl::FuncDecl(func) = parsed.decls.first().expect("expected function")
        else {
            panic!("expected function declaration");
        };
        let crate::ast::Stmt::ExprStmt(expr) = func
            .body
            .as_ref()
            .and_then(|body| body.list.first())
            .expect("expected expression statement")
        else {
            panic!("expected expression statement");
        };
        let crate::ast::Expr::CallExpr(call) = &expr.x else {
            panic!("expected call expression");
        };

        super::set_type_env(super::typeinfer::TypeEnv::new());
        let builtin_kind = super::builtin_call_kind(call);

        let _active_local_names =
            super::ActiveLocalNamesGuard::set(std::iter::once("print".to_string()).collect());
        let shadowed_kind = super::builtin_call_kind(call);
        super::set_type_env(super::typeinfer::TypeEnv::new());

        assert_eq!(builtin_kind, Some(super::ir::BuiltinCallKind::Print));
        assert_eq!(shadowed_kind, None);
    }

    #[test]
    fn it_should_not_treat_shadowed_predeclared_type_call_as_conversion() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                func main() {
                    _ = string("x")
                }
            "#,
        )
        .unwrap();
        let crate::ast::Decl::FuncDecl(func) = parsed.decls.first().expect("expected function")
        else {
            panic!("expected function declaration");
        };
        let crate::ast::Stmt::AssignStmt(assign) = func
            .body
            .as_ref()
            .and_then(|body| body.list.first())
            .expect("expected assignment")
        else {
            panic!("expected assignment");
        };
        let crate::ast::Expr::CallExpr(call) = assign.rhs.first().expect("expected rhs call")
        else {
            panic!("expected call expression");
        };

        super::set_type_env(super::typeinfer::TypeEnv::new());
        let conversion_kind = super::special_type_conversion_kind(call);

        let mut env = super::typeinfer::TypeEnv::new();
        env.set_var(
            "string",
            super::typeinfer::GoType::Func {
                params: vec![super::typeinfer::GoType::String],
                results: vec![super::typeinfer::GoType::String],
                variadic_start: None,
            },
        );
        super::set_type_env(env);
        let shadowed_kind = super::special_type_conversion_kind(call);
        super::set_type_env(super::typeinfer::TypeEnv::new());

        assert_eq!(
            conversion_kind,
            Some(super::ir::SpecialTypeConversionKind::String)
        );
        assert_eq!(shadowed_kind, None);
    }

    #[test]
