    #[test]
    fn compile_emits_pointer_only_impls_for_embedded_interface_method_sets() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                type Reader interface {
                    Read() int
                }

                type Writer interface {
                    Write(int)
                }

                type ReadWriter interface {
                    Reader
                    Writer
                }

                type Source struct{}

                func (s *Source) Read() int { return 1 }
                func (s *Source) Write(n int) {}

                func main() {
                    var src Source
                    var i any = &src
                    _, _ = i.(ReadWriter)
                }
            "#,
        )
        .unwrap();
        let compiled = compile(parsed).unwrap();
        let output = printer::generate(compiled).unwrap();

        assert!(
            output.contains("impl ReadWriter for crate::builtin::GorsPtr<Source>"),
            "{output}"
        );
        assert!(
            output.contains("impl Reader for crate::builtin::GorsPtr<Source>"),
            "{output}"
        );
        assert!(
            output.contains("impl Writer for crate::builtin::GorsPtr<Source>"),
            "{output}"
        );
        assert!(!output.contains("impl ReadWriter for Source"), "{output}");
        assert!(!output.contains("impl Reader for Source"), "{output}");
        assert!(!output.contains("impl Writer for Source"), "{output}");
    }

    #[test]
    fn allow_dead_code_attr_matches_attribute_meta_structurally() {
        let mut existing: Vec<syn::Attribute> = vec![rust! { #[allow(unused, dead_code)] }];

        super::generated_attrs::allow_dead_code(&mut existing);

        assert_eq!(existing.len(), 1);
        let [existing_attr] = existing.as_slice() else {
            return;
        };
        assert!(super::generated_attrs::attribute_allows_dead_code(
            existing_attr
        ));

        let mut missing: Vec<syn::Attribute> =
            vec![rust! { #[allow(unused)] }, rust! { #[doc = "dead_code"] }];

        super::generated_attrs::allow_dead_code(&mut missing);

        assert_eq!(missing.len(), 3);
        assert!(
            missing
                .get(2)
                .is_some_and(super::generated_attrs::attribute_allows_dead_code)
        );

        super::generated_attrs::preserve_for_dce(&mut missing);
        assert!(super::generated_attrs::attrs_preserve_for_dce(&missing));
    }

    #[test]
    fn interface_assertion_implementors_skip_borrowed_interface_field_structs() {
        let mut env = super::typeinfer::TypeEnv::new();
        env.set_type_kind("io.Reader", super::typeinfer::TypeKind::Interface);
        env.set_interface_methods("io.Reader", vec!["Read".to_string()]);
        env.set_type_kind("pkg.Plain", super::typeinfer::TypeKind::Struct);
        env.set_func("pkg.Plain.Read", vec![super::typeinfer::GoType::Int]);
        env.set_pointer_receiver_method("pkg.Plain.Read");
        env.set_type_kind("pkg.Holder", super::typeinfer::TypeKind::Struct);
        env.set_struct_fields(
            "pkg.Holder",
            vec![(
                "inner".to_string(),
                super::typeinfer::GoType::Interface("io.Reader".to_string()),
            )],
        );
        env.set_func("pkg.Holder.Read", vec![super::typeinfer::GoType::Int]);
        env.set_pointer_receiver_method("pkg.Holder.Read");

        super::set_type_env(env);
        let implementors = super::interface_assertion_implementors("io.Reader")
            .into_iter()
            .map(|ty| quote! { #ty }.to_string())
            .collect::<Vec<_>>()
            .join("\n");
        super::set_type_env(super::typeinfer::TypeEnv::new());

        assert!(
            implementors.contains("crate :: builtin :: GorsPtr < pkg :: Plain >"),
            "{implementors}"
        );
        assert!(!implementors.contains("pkg :: Holder"), "{implementors}");
    }

