    #[test]
    fn it_should_forward_pointer_interface_value_receivers_by_value() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                type Reader interface {
                    Read([]byte) (int, error)
                }

                type Source struct {
                    count int
                }

                func (s Source) Read(p []byte) (int, error) {
                    s.count = s.count + 1
                    return s.count, nil
                }

                func take(r Reader) {}

                func main() {
                    src := Source{count: 1}
                    take(&src)
                }
            "#,
        )
        .unwrap();
        let compiled = compile(parsed).unwrap();
        let output = printer::generate(compiled).unwrap();

        assert!(
            output.contains("Source::Read((*__gors_guard).clone(), p)"),
            "{output}"
        );
        assert!(
            !output.contains("Source::Read(&mut *__gors_guard, p)"),
            "{output}"
        );
    }

    #[test]
    fn it_should_forward_pointer_interface_ref_receivers_by_ref() {
        let parsed = parse_file(
            "test.go",
            r#"
                package main

                type Namer interface {
                    Name() string
                }

                type Source struct {
                    name string
                }

                func (s Source) Name() string {
                    return s.name
                }

                func take(n Namer) {}

                func main() {
                    src := Source{name: "alpha"}
                    take(&src)
                }
            "#,
        )
        .unwrap();
        let compiled = compile(parsed).unwrap();
        let output = printer::generate(compiled).unwrap();

        assert!(output.contains("Source::Name(&*__gors_guard)"), "{output}");
        assert!(
            !output.contains("Source::Name((*__gors_guard).clone())"),
            "{output}"
        );
    }

    #[test]
    fn it_should_forward_pointer_interface_value_params_by_value() {
        let tmp = tempfile::tempdir().unwrap();
        write_fixture_file(tmp.path().join("go.mod").as_path(), "module example\n");
        write_fixture_file(
            tmp.path().join("main.go").as_path(),
            r#"
package main

import "example/contract"

type Buffer []byte

func (b *Buffer) WriteString(s string) (int, error) {
	*b = append(*b, s...)
	return len(s), nil
}

type Adapter struct{}

func (a *Adapter) WriteString(w contract.Writer, s string) (int, error) {
	return w.Write([]byte(s))
}

func main() {
	var b Buffer
	var w contract.StringWriter = &b
	w.WriteString("x")
}
"#,
        );
        write_fixture_file(
            tmp.path().join("contract/contract.go").as_path(),
            r#"
package contract

type StringWriter interface {
	WriteString(string) (int, error)
}

type Writer interface {
	Write([]byte) (int, error)
}
"#,
        );

        let output = compile_temp_program(tmp.path());
        let main_rs = output.files.get("main.rs").unwrap();

        assert!(
            main_rs.contains("Buffer::WriteString(&mut *__gors_guard, s)"),
            "{main_rs}"
        );
        assert!(
            !main_rs.contains("Buffer::WriteString(&mut *__gors_guard, &mut s)"),
            "{main_rs}"
        );
    }

