    #[test]
    fn semantic_reachability_graph_records_roots_and_local_edges() {
        let mut modules = BTreeMap::new();
        modules.insert(
            "__main__".to_string(),
            semantic_test_module(
                "__main__",
                rust! {
                    pub fn main() {
                        helper();
                    }

                    fn helper() {}
                },
                true,
            ),
        );

        let graph = super::SemanticReachabilityGraph::from_modules(&modules, true);
        let main_id = semantic_item_id("__main__", super::SemanticItemKind::Function, "main");
        let helper_id = semantic_item_id("__main__", super::SemanticItemKind::Function, "helper");

        assert!(graph.has_consistent_local_edges());
        assert!(graph.roots.contains(&main_id));
        assert!(graph.nodes.contains_key(&helper_id));
        let main_node = graph.nodes.get(&main_id).expect("expected main node");
        assert!(main_node.local_refs.contains(&helper_id), "{main_node:?}");
    }

    #[test]
    fn semantic_reachability_graph_records_external_edges() {
        let mut modules = BTreeMap::new();
        modules.insert(
            "__main__".to_string(),
            semantic_test_module(
                "__main__",
                rust! {
                    pub fn main() {
                        helper();
                    }

                    fn helper() {
                        live::Hello();
                    }

                    fn dead() {
                        unused::Nope();
                    }
                },
                true,
            ),
        );
        modules.insert(
            "live".to_string(),
            semantic_test_module(
                "live",
                rust! {
                    pub fn Hello() {}
                },
                false,
            ),
        );
        modules.insert(
            "unused".to_string(),
            semantic_test_module(
                "unused",
                rust! {
                    pub fn Nope() {}
                },
                false,
            ),
        );

        let graph = super::SemanticReachabilityGraph::from_modules(&modules, true);
        let main_id = semantic_item_id("__main__", super::SemanticItemKind::Function, "main");
        let helper_id = semantic_item_id("__main__", super::SemanticItemKind::Function, "helper");
        let live_id = semantic_item_id("live", super::SemanticItemKind::Function, "Hello");

        assert!(graph.has_consistent_local_edges());
        assert!(graph.nodes.contains_key(&live_id));
        let main_node = graph.nodes.get(&main_id).expect("expected main node");
        assert!(main_node.local_refs.contains(&helper_id), "{main_node:?}");
        let helper_node = graph.nodes.get(&helper_id).expect("expected helper node");
        assert!(
            helper_node
                .external_refs
                .get("live")
                .is_some_and(|refs| refs.contains("Hello")),
            "{helper_node:?}"
        );
        let external_roots = graph.reachable_external_roots_by_module();
        assert!(
            external_roots
                .get("live")
                .is_some_and(|refs| refs.contains("Hello")),
            "{external_roots:?}"
        );
        assert!(!external_roots.contains_key("unused"), "{external_roots:?}");
    }

    #[test]
    fn semantic_reachability_graph_does_not_root_external_trait_impls_from_module_refs() {
        let mut modules = BTreeMap::new();
        modules.insert(
            "__main__".to_string(),
            semantic_test_module(
                "__main__",
                rust! {
                    pub struct byKey;

                    impl crate::sortish::Interface for byKey {
                        fn Swap(&mut self) {
                            builtin::len();
                        }
                    }

                    pub fn main() {
                        sortish::Sort();
                    }
                },
                true,
            ),
        );
        modules.insert(
            "sortish".to_string(),
            semantic_test_module(
                "sortish",
                rust! {
                    pub trait Interface {
                        fn Swap(&mut self);
                    }

                    pub fn Sort() {}
                },
                false,
            ),
        );
        modules.insert(
            "builtin".to_string(),
            semantic_test_module(
                "builtin",
                rust! {
                    pub fn len() {}
                },
                false,
            ),
        );

        let graph = super::SemanticReachabilityGraph::from_modules(&modules, true);
        let external_roots = graph.reachable_external_roots_for_module_roots(
            "__main__",
            &std::collections::HashSet::from(["main".to_string()]),
        );

        assert!(
            external_roots
                .get("sortish")
                .is_some_and(|refs| refs.contains("Sort") && !refs.contains("Interface")),
            "{external_roots:?}"
        );
        assert!(
            !external_roots
                .get("builtin")
                .is_some_and(|refs| refs.contains("len")),
            "{external_roots:?}"
        );
    }

