    #[test]
    fn collect_external_refs_follows_wrapped_imported_value_method_receivers() {
        let file: syn::File = rust! {
            pub fn main() {
                let mut buf = Vec::from([4_u8, 3_u8, 2_u8, 1_u8]);
                let _ = (encoding__binary::LittleEndian).clone().Uint32(buf);
            }
        };
        let module_names = std::collections::HashSet::from(["encoding__binary".to_string()]);

        let refs = super::collect_external_refs(&file.items, &module_names);
        let binary_refs = refs.get("encoding__binary").expect("encoding/binary refs");

        assert!(binary_refs.contains("LittleEndian"), "{refs:?}");
        assert!(binary_refs.contains("LittleEndian::Uint32"), "{refs:?}");
        assert!(!binary_refs.contains("Uint32"), "{refs:?}");
    }

    #[test]
    fn collect_external_refs_follows_locked_imported_value_method_receivers() {
        let file: syn::File = rust! {
            pub fn main() {
                let _ = (encoding__base64::StdEncoding.lock().unwrap()).EncodedLen(4);
            }
        };
        let module_names = std::collections::HashSet::from(["encoding__base64".to_string()]);

        let refs = super::collect_external_refs(&file.items, &module_names);
        let base64_refs = refs.get("encoding__base64").expect("encoding/base64 refs");

        assert!(base64_refs.contains("StdEncoding"), "{refs:?}");
        assert!(base64_refs.contains("StdEncoding::EncodedLen"), "{refs:?}");
        assert!(!base64_refs.contains("EncodedLen"), "{refs:?}");
    }

    #[test]
    fn collect_external_refs_does_not_invent_method_roots_for_external_function_results() {
        let file: syn::File = rust! {
            pub fn main() {
                let _ = strconv::AppendFloat(Vec::<u8>::new(), 1.0, 103, -1, 64).as_bytes();
            }
        };
        let module_names = std::collections::HashSet::from(["strconv".to_string()]);

        let refs = super::collect_external_refs(&file.items, &module_names);
        let strconv_refs = refs.get("strconv").expect("strconv refs");

        assert!(strconv_refs.contains("AppendFloat"), "{refs:?}");
        assert!(!strconv_refs.contains("AppendFloat::as_bytes"), "{refs:?}");
        assert!(!strconv_refs.contains("as_bytes"), "{refs:?}");
    }

    #[test]
    fn reachable_items_follow_locked_method_calls_on_gors_ptr_function_returns() {
        let file: syn::File = syn::parse_quote! {
            pub struct printer;

            fn newPrinter() -> crate::builtin::GorsPtr<printer> {
                crate::builtin::GorsPtr::new(printer)
            }

            pub fn root() {
                let mut p = (newPrinter()).clone();
                (|| { (p.lock().unwrap()).doPrintln() })();
            }

            impl printer {
                fn doPrintln(&mut self) {}
                fn unused(&mut self) {}
            }
        };
        let roots = std::collections::HashSet::from(["root".to_string()]);
        let module_names =
            std::collections::HashSet::from(["builtin".to_string(), "fmt".to_string()]);

        let reachable = super::reachable_stdlib_items(&file.items, &roots, &module_names);

        assert!(
            reachable.names.contains("printer::doPrintln"),
            "{:?}",
            reachable.names
        );
        assert!(
            !reachable.names.contains("printer::unused"),
            "{:?}",
            reachable.names
        );
    }

    #[test]
    fn prune_items_to_roots_retains_stdlib_constants() {
        let roots = std::collections::HashSet::from([
            "PathSeparator".to_string(),
            "PathListSeparator".to_string(),
        ]);
        let module = crate::resolve::resolve_with_roots("os", &roots).unwrap();
        let mut items = module.content.unwrap().1;
        let module_names = std::collections::HashSet::from(["os".to_string()]);

        super::prune_items_to_roots(&mut items, &roots, &module_names);

        let source = prettyplease::unparse(&syn::File {
            shebang: None,
            attrs: vec![],
            items,
        });
        assert!(source.contains("pub const PathSeparator"), "{source}");
        assert!(source.contains("pub const PathListSeparator"), "{source}");
    }

    #[test]
    fn prune_items_to_roots_retains_dereferenced_package_statics() {
        let mut file: syn::File = rust! {
            fn Entry() -> bool {
                !*flag_
            }

            #[allow(non_upper_case_globals)]
            static flag_: std::sync::LazyLock<bool> = std::sync::LazyLock::new(|| true);
        };
        let roots = std::collections::HashSet::from(["Entry".to_string()]);
        let module_names = std::collections::HashSet::new();

        super::prune_items_to_roots(&mut file.items, &roots, &module_names);
        let source = quote! { #file }.to_string();

        assert!(source.contains("fn Entry"), "{source}");
        assert!(source.contains("static flag_"), "{source}");
    }

