    #[test]
    fn it_should_compile_named_type_definition() {
        test(
            r#"
                package main

                type MyInt int
            "#,
            rust! {
                #[derive(Clone, Copy, Default, Eq, Hash, PartialEq, PartialOrd)]
                pub struct MyInt(pub isize);
                impl std::ops::Deref for MyInt {
                    type Target = isize;
                    fn deref(&self) -> &isize { &self.0 }
                }
                impl std::ops::DerefMut for MyInt {
                    fn deref_mut(&mut self) -> &mut isize { &mut self.0 }
                }
                impl From<MyInt> for isize {
                    fn from(value: MyInt) -> isize { value.0 }
                }
                impl std::ops::Add for MyInt {
                    type Output = Self;
                    fn add(self, rhs: Self) -> Self { Self(self.0 + rhs.0) }
                }
                impl std::ops::Sub for MyInt {
                    type Output = Self;
                    fn sub(self, rhs: Self) -> Self { Self(self.0 - rhs.0) }
                }
                impl std::ops::Mul for MyInt {
                    type Output = Self;
                    fn mul(self, rhs: Self) -> Self { Self(self.0 * rhs.0) }
                }
                impl std::ops::Div for MyInt {
                    type Output = Self;
                    fn div(self, rhs: Self) -> Self { Self(self.0 / rhs.0) }
                }
                impl std::ops::Rem for MyInt {
                    type Output = Self;
                    fn rem(self, rhs: Self) -> Self { Self(self.0 % rhs.0) }
                }
                impl std::ops::AddAssign for MyInt {
                    fn add_assign(&mut self, rhs: Self) { self.0 += rhs.0; }
                }
                impl std::ops::SubAssign for MyInt {
                    fn sub_assign(&mut self, rhs: Self) { self.0 -= rhs.0; }
                }
                impl std::ops::MulAssign for MyInt {
                    fn mul_assign(&mut self, rhs: Self) { self.0 *= rhs.0; }
                }
                impl std::ops::DivAssign for MyInt {
                    fn div_assign(&mut self, rhs: Self) { self.0 /= rhs.0; }
                }
                impl std::ops::RemAssign for MyInt {
                    fn rem_assign(&mut self, rhs: Self) { self.0 %= rhs.0; }
                }
                impl std::ops::Neg for MyInt {
                    type Output = Self;
                    fn neg(self) -> Self { Self(-self.0) }
                }
                impl PartialEq<isize> for MyInt {
                    fn eq(&self, other: &isize) -> bool { self.0 == *other }
                }
                impl std::ops::BitAnd for MyInt {
                    type Output = Self;
                    fn bitand(self, rhs: Self) -> Self { Self(self.0 & rhs.0) }
                }
                impl std::ops::BitOr for MyInt {
                    type Output = Self;
                    fn bitor(self, rhs: Self) -> Self { Self(self.0 | rhs.0) }
                }
                impl std::ops::BitXor for MyInt {
                    type Output = Self;
                    fn bitxor(self, rhs: Self) -> Self { Self(self.0 ^ rhs.0) }
                }
                impl std::ops::Not for MyInt {
                    type Output = Self;
                    fn not(self) -> Self { Self(!self.0) }
                }
                impl std::ops::BitAndAssign for MyInt {
                    fn bitand_assign(&mut self, rhs: Self) { self.0 &= rhs.0; }
                }
                impl std::ops::BitOrAssign for MyInt {
                    fn bitor_assign(&mut self, rhs: Self) { self.0 |= rhs.0; }
                }
                impl std::ops::BitXorAssign for MyInt {
                    fn bitxor_assign(&mut self, rhs: Self) { self.0 ^= rhs.0; }
                }
                impl<Rhs> std::ops::Shl<Rhs> for MyInt where isize: std::ops::Shl<Rhs, Output = isize>, {
                    type Output = Self;
                    fn shl(self, rhs: Rhs) -> Self { Self(self.0 << rhs) }
                }
                impl<Rhs> std::ops::Shr<Rhs> for MyInt where isize: std::ops::Shr<Rhs, Output = isize>, {
                    type Output = Self;
                    fn shr(self, rhs: Rhs) -> Self { Self(self.0 >> rhs) }
                }
                impl<Rhs> std::ops::ShlAssign<Rhs> for MyInt where isize: std::ops::ShlAssign<Rhs>, {
                    fn shl_assign(&mut self, rhs: Rhs) { self.0 <<= rhs; }
                }
                impl<Rhs> std::ops::ShrAssign<Rhs> for MyInt where isize: std::ops::ShrAssign<Rhs>, {
                    fn shr_assign(&mut self, rhs: Rhs) { self.0 >>= rhs; }
                }
            },
        );
    }

