    #[test]
    fn it_should_not_keep_inherent_methods_by_bare_name() {
        let file: syn::File = rust! {
            pub struct A;
            pub struct B;

            impl A {
                pub fn String(&mut self) -> String {
                    String::new()
                }

                pub fn Used(&mut self) {}
            }

            impl B {
                pub fn String(&mut self) -> String {
                    String::new()
                }
            }

            pub fn String() -> String {
                String::new()
            }
        };
        let names = std::collections::HashSet::from([
            "A".to_string(),
            "B".to_string(),
            "String".to_string(),
            super::impl_method_reachability_name("A", "Used"),
        ]);
        let roots = names.clone();
        let item_names = super::item_reachability_names(&file.items);
        let top_level_names = super::top_level_item_names(&file.items);

        let kept = file
            .items
            .iter()
            .filter_map(|item| {
                super::reachable_item_for_names(item, &names, &item_names, &top_level_names, &roots)
            })
            .collect::<Vec<_>>();
        let output = quote::quote!(#(#kept)*).to_string();

        assert!(output.contains("pub fn Used"), "{output}");
        assert!(!output.contains("impl B"), "{output}");
        assert!(!output.contains("pub fn String (& mut self)"), "{output}");
    }

    #[test]
    fn it_should_follow_field_method_calls_through_pointer_cells() {
        let file: syn::File = rust! {
            pub struct fmt;
            pub struct pp {
                fmt: fmt,
            }

            impl fmt {
                pub fn init(&mut self, _arg: crate::builtin::GorsPtr<fmt>) {}
            }

            pub fn newPrinter() -> crate::builtin::GorsPtr<pp> {
                let mut p = Default::default();
                (|| {
                    let arg = crate::builtin::GorsPtr::new({
                        let field = (p.lock().unwrap().fmt).clone();
                        field
                    });
                    (p.lock().unwrap().fmt).init(arg);
                })();
                (p).clone()
            }

            pub fn root() {
                let _ = newPrinter();
            }
        };
        let roots = std::collections::HashSet::from(["root".to_string()]);
        let module_names = std::collections::HashSet::from(["builtin".to_string()]);

        let reachable = super::reachable_stdlib_items(&file.items, &roots, &module_names);

        assert!(
            reachable.names.contains("newPrinter"),
            "{:?}",
            reachable.names
        );
        assert!(
            reachable
                .names
                .contains(&super::impl_method_reachability_name("fmt", "init")),
            "{:?}",
            reachable.names
        );

        let item_names = super::item_reachability_names(&file.items);
        let top_level_names = super::top_level_item_names(&file.items);
        let kept = file
            .items
            .iter()
            .filter_map(|item| {
                super::reachable_item_for_names(
                    item,
                    &reachable.names,
                    &item_names,
                    &top_level_names,
                    &roots,
                )
            })
            .collect::<Vec<_>>();
        let output = quote::quote!(#(#kept)*).to_string();

        assert!(output.contains("pub fn init"), "{output}");
    }

    #[test]
    fn it_should_preserve_runtime_interface_hooks_during_dce() {
        let file: syn::File = rust! {
            pub trait Interface {
                fn __gors_as_any(&self) -> Option<&dyn std::any::Any>;
                fn Len(&mut self) -> isize;
            }

            pub struct Values;

            impl Interface for Values {
                fn __gors_as_any(&self) -> Option<&dyn std::any::Any> {
                    Some(self)
                }

                fn Len(&mut self) -> isize {
                    0
                }
            }

            pub fn root(mut value: Values) -> isize {
                Interface::Len(&mut value)
            }
        };
        let roots = std::collections::HashSet::from(["root".to_string()]);
        let module_names = std::collections::HashSet::new();

        let reachable = super::reachable_stdlib_items(&file.items, &roots, &module_names);
        let item_names = super::item_reachability_names(&file.items);
        let top_level_names = super::top_level_item_names(&file.items);

        let trait_item = file
            .items
            .iter()
            .find(|item| matches!(item, syn::Item::Trait(_)))
            .and_then(|item| {
                super::reachable_item_for_names(
                    item,
                    &reachable.names,
                    &item_names,
                    &top_level_names,
                    &roots,
                )
            })
            .and_then(|item| match item {
                syn::Item::Trait(item_trait) => Some(item_trait),
                _ => None,
            })
            .expect("expected trait");
        assert!(trait_item.items.iter().any(|item| {
            matches!(item, syn::TraitItem::Fn(func) if func.sig.ident == "__gors_as_any")
        }));

        let impl_item = file
            .items
            .iter()
            .find(|item| matches!(item, syn::Item::Impl(_)))
            .and_then(|item| {
                super::reachable_item_for_names(
                    item,
                    &reachable.names,
                    &item_names,
                    &top_level_names,
                    &roots,
                )
            })
            .and_then(|item| match item {
                syn::Item::Impl(item_impl) => Some(item_impl),
                _ => None,
            })
            .expect("expected impl");
        assert!(impl_item.items.iter().any(|item| {
            matches!(item, syn::ImplItem::Fn(func) if func.sig.ident == "__gors_as_any")
        }));
    }

