    #[test]
    fn it_should_compile_defer_statement() {
        test(
            r#"
                package main

                func cleanup() {}

                func main() {
                    defer cleanup()
                }
            "#,
            rust! {
                fn cleanup() {}
                pub fn main() {
                    let mut __gors_defer_stack = {
                        struct __GorsDeferStack(Vec<Box<dyn FnOnce()>>);
                        impl Drop for __GorsDeferStack {
                            fn drop(&mut self) {
                                while let Some(__gors_defer) = self.0.pop() {
                                    __gors_defer();
                                }
                                crate::builtin::resume_unrecovered_panic();
                            }
                        }
                        __GorsDeferStack(Vec::new())
                    };
                    let __gors_panic_result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                        {
                            __gors_defer_stack.0.push(Box::new(move || { cleanup(); }));
                        }
                    }));
                    if let Err(__gors_panic_payload) = __gors_panic_result {
                        crate::builtin::set_recover_payload_box(__gors_panic_payload);
                    }
                }
            },
        );
    }

